  stt_builder_ = stt::makeSteinerTreeBuilder();
  dft_ = dft::makeDft();
  estimate_parasitics_ = est::makeEstimateParasitics();

  // Init components.
  Ord_Init(tcl_interp);
  // Import TCL scripts.
  utl::evalTclInit(tcl_interp, ord::ord_tcl_inits);

  initLogger(logger_, tcl_interp);
