  gui::initGui(tcl_interp, db_, sta_, logger_);
  odb::initOdb(tcl_interp);
  upf::initUpf(tcl_interp);
  ifp::initInitFloorplan(tcl_interp);
  initDbSta(sta_, logger_, tcl_interp, db_);
  initResizer(resizer_,
              tcl_interp,
              logger_,
              db_,
              sta_,
              stt_builder_,
              global_router_,
